import{_ as e,o as a,c as n,ag as r}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Plugins Overview","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/index.md","filePath":"plugins/index.md"}'),i={name:"plugins/index.md"};function s(d,t,l,o,h,g){return a(),n("div",null,[...t[0]||(t[0]=[r(`<h1 id="plugins-overview" tabindex="-1">Plugins Overview <a class="header-anchor" href="#plugins-overview" aria-label="Permalink to &quot;Plugins Overview&quot;">​</a></h1><p>R3 ships with <strong>30 plugins</strong> covering server administration, moderation, statistics, anti-abuse, and more. All plugins are optional and individually configurable.</p><h2 id="enabling-plugins" tabindex="-1">Enabling Plugins <a class="header-anchor" href="#enabling-plugins" aria-label="Permalink to &quot;Enabling Plugins&quot;">​</a></h2><p>Add a <code>[[plugins]]</code> entry to your <code>referee.toml</code> for each plugin you want:</p><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">plugins</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">name = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;admin&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">enabled = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">plugins</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">settings</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">max_warnings = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span></span></code></pre></div><p>Set <code>enabled = false</code> to disable a plugin without removing its configuration.</p><h2 id="plugin-categories" tabindex="-1">Plugin Categories <a class="header-anchor" href="#plugin-categories" aria-label="Permalink to &quot;Plugin Categories&quot;">​</a></h2><h3 id="core-administration" tabindex="-1">Core Administration <a class="header-anchor" href="#core-administration" aria-label="Permalink to &quot;Core Administration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><a href="/plugins/admin.html">admin</a></td><td>Core command handler — !kick, !ban, !warn, !tempban, and 50+ commands</td></tr><tr><td><a href="/plugins/poweradminurt.html">poweradminurt</a></td><td>Urban Terror specific commands — !slap, !nuke, !gear, team management</td></tr></tbody></table><h3 id="moderation" tabindex="-1">Moderation <a class="header-anchor" href="#moderation" aria-label="Permalink to &quot;Moderation&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><a href="/plugins/censor.html">censor</a></td><td>Filters offensive language from chat with regex patterns</td></tr><tr><td><a href="/plugins/censorurt.html">censorurt</a></td><td>Urban Terror specific name/clan tag censoring</td></tr><tr><td><a href="/plugins/spamcontrol.html">spamcontrol</a></td><td>Prevents chat flooding and message repetition</td></tr><tr><td><a href="/plugins/tk.html">tk</a></td><td>Team kill monitoring and automatic penalties</td></tr><tr><td><a href="/plugins/spawnkill.html">spawnkill</a></td><td>Detects and punishes spawn killing</td></tr></tbody></table><h3 id="player-management" tabindex="-1">Player Management <a class="header-anchor" href="#player-management" aria-label="Permalink to &quot;Player Management&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><a href="/plugins/welcome.html">welcome</a></td><td>Greets new and returning players</td></tr><tr><td><a href="/plugins/makeroom.html">makeroom</a></td><td>Kicks lowest-level player to make room for admins</td></tr><tr><td><a href="/plugins/nickreg.html">nickreg</a></td><td>Nickname registration and impostor protection</td></tr><tr><td><a href="/plugins/namechecker.html">namechecker</a></td><td>Name policy enforcement (duplicates, forbidden names, change limits)</td></tr><tr><td><a href="/plugins/specchecker.html">specchecker</a></td><td>Kicks idle spectators when the server is busy</td></tr><tr><td><a href="/plugins/login.html">login</a></td><td>Requires admins to authenticate before using commands</td></tr><tr><td><a href="/plugins/follow.html">follow</a></td><td>Follow a player and get notifications about their activity</td></tr></tbody></table><h3 id="anti-abuse" tabindex="-1">Anti-Abuse <a class="header-anchor" href="#anti-abuse" aria-label="Permalink to &quot;Anti-Abuse&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><a href="/plugins/afk.html">afk</a></td><td>Detects and handles AFK players</td></tr><tr><td><a href="/plugins/pingwatch.html">pingwatch</a></td><td>Monitors and kicks high-ping players</td></tr><tr><td><a href="/plugins/vpncheck.html">vpncheck</a></td><td>Blocks VPN/proxy connections</td></tr><tr><td><a href="/plugins/countryfilter.html">countryfilter</a></td><td>GeoIP-based country filtering</td></tr><tr><td><a href="/plugins/callvote.html">callvote</a></td><td>Controls and filters in-game callvotes</td></tr></tbody></table><h3 id="statistics" tabindex="-1">Statistics <a class="header-anchor" href="#statistics" aria-label="Permalink to &quot;Statistics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><a href="/plugins/stats.html">stats</a></td><td>In-memory K/D tracking with !stats and !topstats</td></tr><tr><td><a href="/plugins/xlrstats.html">xlrstats</a></td><td>Extended live rankings with ELO skill tracking</td></tr><tr><td><a href="/plugins/headshotcounter.html">headshotcounter</a></td><td>Headshot streak tracking and aimbot detection</td></tr><tr><td><a href="/plugins/spree.html">spree</a></td><td>Killing spree announcements</td></tr><tr><td><a href="/plugins/firstkill.html">firstkill</a></td><td>First kill of each round announcements</td></tr><tr><td><a href="/plugins/flagannounce.html">flagannounce</a></td><td>Flag event announcements (CTF)</td></tr></tbody></table><h3 id="chat-logging" tabindex="-1">Chat &amp; Logging <a class="header-anchor" href="#chat-logging" aria-label="Permalink to &quot;Chat &amp; Logging&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><a href="/plugins/chatlogger.html">chatlogger</a></td><td>Logs all chat to daily rotating files and database</td></tr><tr><td><a href="/plugins/customcommands.html">customcommands</a></td><td>User-defined text commands (!rules, !discord, etc.)</td></tr></tbody></table><h3 id="server-management" tabindex="-1">Server Management <a class="header-anchor" href="#server-management" aria-label="Permalink to &quot;Server Management&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Plugin</th><th>Description</th></tr></thead><tbody><tr><td><a href="/plugins/adv.html">adv</a></td><td>Rotating server advertisement messages</td></tr><tr><td><a href="/plugins/scheduler.html">scheduler</a></td><td>Runs commands on game events (round start, map change, etc.)</td></tr><tr><td><a href="/plugins/mapconfig.html">mapconfig</a></td><td>Executes map-specific RCON commands on map change</td></tr></tbody></table><h2 id="plugin-dependencies" tabindex="-1">Plugin Dependencies <a class="header-anchor" href="#plugin-dependencies" aria-label="Permalink to &quot;Plugin Dependencies&quot;">​</a></h2><p>Some plugins depend on others:</p><ul><li><strong>censor</strong>, <strong>spamcontrol</strong>, <strong>tk</strong>, <strong>login</strong>, <strong>follow</strong>, <strong>makeroom</strong>, <strong>customcommands</strong> require the <strong>admin</strong> plugin</li><li><strong>callvote</strong>, <strong>spawnkill</strong>, <strong>headshotcounter</strong>, <strong>namechecker</strong>, <strong>specchecker</strong> require the <strong>iourt43</strong> parser</li></ul><p>The admin plugin should always be loaded first.</p><h2 id="permission-levels" tabindex="-1">Permission Levels <a class="header-anchor" href="#permission-levels" aria-label="Permalink to &quot;Permission Levels&quot;">​</a></h2><p>Many plugins reference permission levels. R3 uses this hierarchy:</p><table tabindex="0"><thead><tr><th>Level</th><th>Value</th><th>Description</th></tr></thead><tbody><tr><td>Guest</td><td>0</td><td>Default for new players</td></tr><tr><td>User</td><td>1</td><td>Registered players</td></tr><tr><td>Regular</td><td>2</td><td>Trusted regulars</td></tr><tr><td>Moderator</td><td>20</td><td>Can warn, kick, manage players</td></tr><tr><td>Admin</td><td>40</td><td>Can tempban, use advanced commands</td></tr><tr><td>Senior Admin</td><td>60</td><td>Can permanently ban, configure server</td></tr><tr><td>Super Admin</td><td>80</td><td>Full access to all commands</td></tr></tbody></table>`,28)])])}const m=e(i,[["render",s]]);export{p as __pageData,m as default};
